import { access, mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const projectRoot = process.cwd();
const repoRoot = path.resolve(projectRoot, "..");
const changelogPath = path.join(repoRoot, "CHANGELOG.md");
const generatedFilePath = path.join(projectRoot, "src", "lib", "generated-changelog.ts");

function buildGeneratedSource(changelogContent) {
  return [
    "// This file is generated by web/scripts/sync-site-documents.mjs.",
    "// Do not edit it manually.",
    `export const GENERATED_CHANGELOG_CONTENT = ${JSON.stringify(changelogContent)};`,
    "",
  ].join("\n");
}

async function main() {
  let changelogContent;

  try {
    changelogContent = await readFile(changelogPath, "utf8");
  } catch (error) {
    if (error?.code !== "ENOENT") {
      throw error;
    }

    try {
      await access(generatedFilePath);
      console.warn(
        `Skipping root changelog sync because ${changelogPath} is not available in this build context. Keeping committed ${generatedFilePath}.`,
      );
      return;
    } catch {
      throw new Error(
        `Could not find ${changelogPath}, and no committed generated changelog exists at ${generatedFilePath}.`,
      );
    }
  }

  const generatedSource = buildGeneratedSource(changelogContent);

  await mkdir(path.dirname(generatedFilePath), { recursive: true });
  await writeFile(generatedFilePath, generatedSource, "utf8");
}

main().catch((error) => {
  console.error("Failed to sync site documents.", error);
  process.exitCode = 1;
});